[{"word_id": "ueberstehen-v", "display": "überstehen", "lemma": "überstehen", "pos": "verb", "level": "B2", "source": "freq", "candidates": [{"tid": "10968626", "de": "Schwarzer Humor hilft mir, schwere Zeiten zu überstehen.", "en": "Dark humor helps me get over tough times.", "ru": "Чёрный юмор помогает мне пережить тяжёлые времена."}, {"tid": "2466507", "de": "Der Patient wird den Sommer nicht überstehen.", "en": "That patient cannot hold out through the summer.", "ru": "Пациент не переживёт лето."}, {"tid": "884504", "de": "Wie haben Sie die Narkose überstanden?", "en": "How did you get through anesthesia?", "ru": "Как Вы перенесли наркоз?"}, {"tid": "12554907", "de": "Es ist ein Wunder, daß unser Haus das Erdbeben überstanden hat.", "en": "It's a miracle our house survived the earthquake.", "ru": "Удивительно, что наш дом пережил землетрясение."}, {"tid": "2221246", "de": "Das Schlimmste ist überstanden.", "en": "The worst is over."}]}, {"word_id": "zuruecktreten-v", "display": "zurücktreten", "lemma": "zurücktreten", "pos": "verb", "level": "B2", "source": "freq", "candidates": [{"tid": "5263158", "de": "Der Ministerpräsident und sein Kabinett sind zurückgetreten.", "en": "The premier and his cabinet colleagues resigned.", "ru": "Премьер-министр и его кабинет подали в отставку."}, {"tid": "5405345", "de": "Um weiter zu springen, muss man einen Schritt zurücktreten.", "en": "To jump farther, one must take a step back.", "ru": "Чтобы дальше прыгнуть, надо сделать шаг назад."}, {"tid": "1924625", "de": "Die gesamte Regierung ist zurückgetreten.", "en": "The whole government has resigned.", "ru": "Министерство в полном составе подало в отставку."}, {"tid": "642652", "de": "Der Premierminister ist zurückgetreten.", "en": "The Prime Minister has resigned.", "ru": "Премьер-министр подал в отставку."}, {"tid": "664918", "de": "Sie entschloss sich, zurückzutreten.", "en": "She decided to resign.", "ru": "Она решила уволиться."}]}]
